{"new_text":"function buildHolodeck(theme: ArenaTheme): Group {
  const env = new Group();
  const accentColor = new Color(theme.accent);

  // ---- SOLID GROUND PLANE (fallback base under terrain tiles) ----
  const groundGeo = new PlaneGeometry(120, 120);
  const groundMat = new MeshStandardMaterial({ color: new Color(theme.wall), roughness: 0.95, metalness: 0.0 });
  const ground = new Mesh(groundGeo, groundMat);
  ground.rotation.x = -Math.PI / 2;
  ground.position.y = -0.05;
  env.add(ground);

  if (loadedModels) {
    // ---- TERRAIN TILES: cover play area with Kenney terrain ----
    // Measure terrain tile size with Box3
    const terrainBox = new Box3().setFromObject(loadedModels.terrain);
    const tileSize = terrainBox.max.x - terrainBox.min.x;
    const tileScale = 2.0;
    const scaledTile = tileSize * tileScale;
    // Lay a grid of terrain tiles
    for (let gx = -3; gx <= 3; gx++) {
      for (let gz = -3; gz <= 3; gz++) {
        const t = loadedModels.terrain.clone();
        t.scale.setScalar(tileScale);
        t.position.set(gx * scaledTile, 0, gz * scaledTile);
        env.add(t);
      }
    }

    // Terrain edge pieces along the perimeter for natural falloff
    const edgePositions: [number, number, number, number][] = [
      [-4 * scaledTile, 0, 0, 0],
      [4 * scaledTile, 0, 0, Math.PI],
      [0, 0, -4 * scaledTile, Math.PI / 2],
      [0, 0, 4 * scaledTile, -Math.PI / 2],
    ];
    for (const [ex, ey, ez, erot] of edgePositions) {
      const side = loadedModels.terrainSide.clone();
      side.scale.setScalar(tileScale * 1.5);
      side.position.set(ex, ey, ez);
      side.rotation.y = erot;
      env.add(side);
    }

    // Terrain ramps for elevation variety
    const ramp1 = loadedModels.terrainRampLarge.clone();
    ramp1.scale.setScalar(2.0);
    ramp1.position.set(18, 0, -12);
    ramp1.rotation.y = Math.PI * 0.3;
    env.add(ramp1);

    const ramp2 = loadedModels.terrainRamp.clone();
    ramp2.scale.setScalar(2.0);
    ramp2.position.set(-16, 0, 10);
    ramp2.rotation.y = Math.PI * 1.2;
