  }

  // Subtle pad edge glow ring (thin accent)
  const padEdge = new Mesh(
    new TorusGeometry(1.8, 0.02, 8, 48),
    new MeshBasicMaterial({ color: accentColor, transparent: true, opacity: 0.5 })
  );
  padEdge.rotation.x = -Math.PI / 2;
  padEdge.position.set(0, 0.12, -4);
  env.add(padEdge);

  // ---- LIGHTING (bright daytime) ----
  const ambient = new AmbientLight(0xffffff, 0.7);
  env.add(ambient);
  const dirLight = new DirectionalLight(0xfff8e8, 1.2);
  dirLight.position.set(5, 12, 8);
  dirLight.castShadow = false;
  env.add(dirLight);
  // Fill light from opposite side
  const fillLight = new DirectionalLight(0x8899cc, 0.4);
  fillLight.position.set(-5, 6, -4);
  env.add(fillLight);
  // Accent light on pad
  const padLight = new PointLight(new Color(theme.accent).getHex(), 0.6, 12);
  padLight.position.set(0, 2, -4);
  env.add(padLight);

  return env;
}
